// Step 1: Read 8 integers into the array

printf("Enter 8 numbers for the array: ");

for (int i = 0; i < 8; i++) {

scanf("%d", &arr[i]);  // Reads arr[0], arr[1], ..., arr[7]

}

// Step 2: Now read X and Y (only once, outside the loop)

printf("Enter two indices (0-7): ");

scanf("%d %d", &X, &Y);

// Step 3: Calculate and print the sum

int sum = arr[X] + arr[Y];

printf("Sum of arr[%d] and arr[%d] is: %d", X, Y, sum);

return 0;

}

